 else {
        checkIncrementAndDecrement(data,loopVariables,loopBody);
      }
    }
  }
 else   if (node.getParent() instanceof ASTForStatement) {
    final ASTStatement loopBody=node.getParent().getFirstChildOfType(ASTStatement.class);
